import"./modulepreload-polyfill.js";document.getElementById("useOpenDyslexic").addEventListener("change",function(t){chrome.storage.sync.set({useOpenDyslexic:t.target.checked},function(){const e=document.getElementById("status");e.textContent="Settings saved",e.className="status success",e.style.display="block",setTimeout(()=>e.style.display="none",2e3)})});document.addEventListener("DOMContentLoaded",function(){chrome.storage.sync.get(["useOpenDyslexic"],function(t){document.getElementById("useOpenDyslexic").checked=t.useOpenDyslexic||!1})});
